import Navbar from "../../components/Navbar/Navbar";
import SummaryCard from '../../components/SummaryCard/SummaryCard';
import TransactionRow from '../../components/TransactionRow/TransactionRow';
import TransactionForm from '../../components/TransactionForm/TransactionForm';
import "./Dashboard.css";
import { useState } from "react";

function Dashboard() {
  const [transactions, setTransactions] = useState([]);
  const [incomeAmount, setIncomeAmount] = useState("0");
  const [expenseAmount, setExpenseAmount] = useState("0");
  return (
    <>
    <div className="dashboard-container">
      <Navbar />
      <p className="main-heading">Summary</p>
      <div className="summary-container">
        <SummaryCard title="Income" incomeAmount={incomeAmount} className="income"/>
        {/* <SummaryCard title="Expenses" expenseAmount={expenseAmount} className="expenses"/> */}
        <SummaryCard title="Balance" incomeAmount="60000" className="balance"/>
      </div>
      <p className="main-heading">Recent Transactions</p>   
      {transactions.map((transaction) => (
        <TransactionRow key={transaction.id} transaction={transaction} transactions={transactions} setTransactions={setTransactions} incomeincomeAmount={incomeAmount} setIncomeincomeAmount = {setIncomeAmount}/>
      ))} 
      <TransactionForm transactions={transactions} setTransactions={setTransactions} incomeincomeAmount={incomeAmount} setIncomeincomeAmount = {setIncomeAmount}/>  
    </div>
    </>
  );
}

export default Dashboard;
